// Same components and thresholds as the app's Risk Radar (see README).
const tickers = ['^VIX', 'GC=F', 'CL=F', 'EURUSD=X'];
const out = {};
for (const t of tickers) {
  const url = `https://query1.finance.yahoo.com/v8/finance/chart/${encodeURIComponent(t)}?range=5d&interval=1d`;
  const resp = await this.helpers.httpRequest({ url, headers: { 'User-Agent': 'Mozilla/5.0' }, json: true });
  const closes = (resp.chart.result[0].indicators.quote[0].close || []).filter((x) => x != null);
  const level = closes.at(-1);
  const prev = closes.at(-2);
  out[t] = { level, chg: prev ? +((level - prev) / prev * 100).toFixed(2) : null };
}
const s = {};
s.vix = out['^VIX'].level < 18 ? 0 : out['^VIX'].level <= 25 ? 1 : 2;
if ((out['^VIX'].chg ?? 0) > 10) s.vix = Math.min(2, s.vix + 1);
s.gold = (out['GC=F'].chg ?? 0) > 2.5 ? 2 : (out['GC=F'].chg ?? 0) > 1.0 ? 1 : 0;
const oilAbs = Math.abs(out['CL=F'].chg ?? 0);
s.oil = oilAbs > 6 ? 2 : oilAbs > 3 ? 1 : 0;
s.usd = (out['EURUSD=X'].chg ?? 0) < -1.2 ? 2 : (out['EURUSD=X'].chg ?? 0) < -0.5 ? 1 : 0;
const score = s.vix + s.gold + s.oil + s.usd;
return [{ json: { score, max: 8, hot: score >= 4, detail: JSON.stringify({ s, out }) } }];
